// ── Cache Config with per-cache TTL ────────────────────────────────
import org.springframework.cache.annotation.EnableCaching;
import org.springframework.context.annotation.*;
import org.springframework.data.redis.cache.*;
import org.springframework.data.redis.connection.RedisConnectionFactory;
import java.time.Duration;
import java.util.HashMap;

@EnableCaching
@Configuration
public class CacheConfig {
    @Bean
    public RedisCacheManager cacheManager(RedisConnectionFactory cf) {
        RedisCacheConfiguration defaults = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofMinutes(10))
            .disableCachingNullValues();

        HashMap<String, RedisCacheConfiguration> cacheConfigs = new HashMap<>();
        // Short TTL for user XP (changes frequently)
        cacheConfigs.put("userXp", defaults.entryTtl(Duration.ofMinutes(1)));
        // Long TTL for topic content (changes rarely)
        cacheConfigs.put("topicContent", defaults.entryTtl(Duration.ofHours(6)));

        return RedisCacheManager.builder(cf)
            .cacheDefaults(defaults)
            .withInitialCacheConfigurations(cacheConfigs)
            .build();
    }
}

