import org.springframework.cache.annotation.*;
import org.springframework.stereotype.Service;

@Service
public class TopicService {

    // Cache-aside: check cache → miss → call method → store result
    // Key: "devlearn:topicContent::42"
    @Cacheable(cacheNames = "topicContent", key = "#topicId")
    public TopicDto getTopicContent(Long topicId) {
        System.out.println("Cache MISS — loading from DB: " + topicId);
        return topicRepository.findById(topicId).map(TopicDto::from).orElseThrow();
    }

    // Evict on update so next read fetches fresh data
    @CacheEvict(cacheNames = "topicContent", key = "#topicId")
    @Transactional
    public void updateTopic(Long topicId, UpdateTopicRequest req) {
        // DB update — cache entry for this topic is removed
        topicRepository.findById(topicId).ifPresent(t -> t.applyUpdate(req));
    }

    // Evict ALL entries in topicContent cache (admin bulk update)
    @CacheEvict(cacheNames = "topicContent", allEntries = true)
    public void evictAllTopics() { }
}

// ── Redis Sorted Set commands for leaderboard ─────────────────────
/*
ZADD leaderboard 1200 user:1        → add/update user:1 with score 1200
ZADD leaderboard 2500 user:2        → add/update user:2 with score 2500
ZADD leaderboard 800  user:3        → add user:3 with score 800

ZREVRANK leaderboard user:1         → rank 1 (0-indexed, highest score first)
ZSCORE  leaderboard user:1          → 1200.0
ZREVRANGE leaderboard 0 9 WITHSCORES → top 10 with scores
ZRANGE  leaderboard 0 -1 REV WITHSCORES → all, highest to lowest
ZCARD   leaderboard                 → total member count
ZINCRBY leaderboard 50 user:1       → increment user:1 score by 50 → 1250
*/

// ── Spring Data Redis — Leaderboard Service ────────────────────────
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.data.redis.core.ZSetOperations;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class LeaderboardService {
    private static final String BOARD_KEY = "devlearn:leaderboard";
    private final RedisTemplate<String, String> redis;

    public LeaderboardService(RedisTemplate<String, String> redis) {
        this.redis = redis;
    }

    // Add or update score (ZADD replaces if key exists)
    public void updateScore(Long userId, double xp) {
        redis.opsForZSet().add(BOARD_KEY, "user:" + userId, xp);
    }

    // Increment score (atomic ZINCRBY)
    public Double addXp(Long userId, double xpGained) {
        return redis.opsForZSet().incrementScore(BOARD_KEY, "user:" + userId, xpGained);
    }

    // Get rank (0-indexed, highest score = rank 0)
    public Long getRank(Long userId) {
        Long rank = redis.opsForZSet().reverseRank(BOARD_KEY, "user:" + userId);
        return rank != null ? rank + 1 : null; // 1-indexed for display
    }

    // Get top N users with scores
    public List<String> getTopN(int n) {
        Set<ZSetOperations.TypedTuple<String>> topN =
            redis.opsForZSet().reverseRangeWithScores(BOARD_KEY, 0, n - 1);
        List<String> result = new ArrayList<>();
        if (topN == null) return result;
        int rank = 1;
        for (ZSetOperations.TypedTuple<String> entry : topN) {
            result.add("#" + rank++ + " " + entry.getValue()
                + " — " + entry.getScore().intValue() + " XP");
        }
        return result;
    }
}

// ── Rate limiter using Redis INCR + EXPIRE ─────────────────────────
@Service
public class RedisRateLimiter {
    private final RedisTemplate<String, String> redis;
    RedisRateLimiter(RedisTemplate<String, String> redis) { this.redis = redis; }

    public boolean isAllowed(Long userId, int maxPerMinute) {
        String key = "ratelimit:" + userId + ":" + (System.currentTimeMillis() / 60_000);
        Long count = redis.opsForValue().increment(key);
        if (count == 1) redis.expire(key, java.time.Duration.ofSeconds(60)); // set TTL on first
        return count <= maxPerMinute;
    }
}

