import java.util.*;
import java.util.function.*;

public class Q1 {
    static class CacheAsideStore<K, V> {
        private final int maxSize;
        private final Function<K, V> loader;
        private int hits = 0, misses = 0;
        private final Map<K, V> cache;

        CacheAsideStore(int maxSize, Function<K, V> loader) {
            this.maxSize = maxSize;
            this.loader = loader;
            this.cache = new LinkedHashMap<>(maxSize, 0.75f, true) {
                @Override
                protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
                    return size() > maxSize;
                }
            };
        }

        V get(K key) {
            V cached = cache.get(key);
            if (cached != null) { hits++; return cached; }
            misses++;
            V loaded = loader.apply(key);
            cache.put(key, loaded);
            return loaded;
        }

        String stats() {
            int total = hits + misses;
            double rate = total == 0 ? 0 : (hits * 100.0 / total);
            return String.format("hits=%d misses=%d rate=%.0f%%", hits, misses, rate);
        }
    }

    public static void main(String[] args) {
        CacheAsideStore<String, String> store = new CacheAsideStore<>(3, key -> {
            System.out.println("DB load: " + key);
            return key.toUpperCase();
        });

        System.out.println(store.get("alice"));
        System.out.println(store.get("alice"));
        System.out.println(store.get("bob"));
        System.out.println(store.get("alice"));
        System.out.println(store.stats());
    }
}

