import java.util.*;

public class Q2 {
    static class Leaderboard {
        private final Map<String, Double> scores = new HashMap<>();
        private final TreeMap<Double, TreeSet<String>> ranked = new TreeMap<>(Comparator.reverseOrder());

        void addScore(String user, double score) {
            Double old = scores.remove(user);
            if (old != null) {
                TreeSet<String> bucket = ranked.get(old);
                if (bucket != null) { bucket.remove(user); if (bucket.isEmpty()) ranked.remove(old); }
            }
            scores.put(user, score);
            ranked.computeIfAbsent(score, k -> new TreeSet<>()).add(user);
        }

        void incrementScore(String user, double delta) {
            addScore(user, scores.getOrDefault(user, 0.0) + delta);
        }

        double getScore(String user) { return scores.getOrDefault(user, 0.0); }

        int getRank(String user) {
            if (!scores.containsKey(user)) return -1;
            int rank = 1;
            for (Map.Entry<Double, TreeSet<String>> entry : ranked.entrySet()) {
                if (entry.getValue().contains(user)) return rank;
                rank += entry.getValue().size();
            }
            return -1;
        }

        List<String> getTopN(int n) {
            List<String> result = new ArrayList<>();
            int rank = 1;
            for (Map.Entry<Double, TreeSet<String>> entry : ranked.entrySet()) {
                for (String user : entry.getValue()) {
                    if (rank > n) break;
                    result.add("#" + rank++ + ". " + user + ": " + (int)(double)entry.getKey());
                }
                if (rank > n) break;
            }
            return result;
        }
    }

    public static void main(String[] args) {
        Leaderboard lb = new Leaderboard();
        lb.addScore("alice", 1200);
        lb.addScore("bob",   2500);
        lb.addScore("carol", 800);
        lb.incrementScore("alice", 400);

        System.out.println("Bob rank: "   + lb.getRank("bob"));
        System.out.println("Alice rank: " + lb.getRank("alice"));
        System.out.println("Alice score: "+ (int) lb.getScore("alice"));
        lb.getTopN(3).forEach(System.out::println);
    }
}

