import java.util.*;

public class Q3 {
    static class SlidingWindowRateLimiter {
        private final Map<String, LinkedList<Long>> windows = new HashMap<>();

        boolean isAllowed(String userId, int maxRequests, long windowMs) {
            long now = System.currentTimeMillis();
            LinkedList<Long> timestamps = windows.computeIfAbsent(userId, k -> new LinkedList<>());

            // Prune expired entries outside the window
            while (!timestamps.isEmpty() && timestamps.peekFirst() <= now - windowMs) {
                timestamps.pollFirst();
            }

            if (timestamps.size() < maxRequests) {
                timestamps.addLast(now);
                return true;
            }
            return false;
        }
    }

    public static void main(String[] args) throws InterruptedException {
        SlidingWindowRateLimiter limiter = new SlidingWindowRateLimiter();
        long windowMs = 200;
        int max = 3;

        System.out.println(limiter.isAllowed("u1", max, windowMs));
        System.out.println(limiter.isAllowed("u1", max, windowMs));
        System.out.println(limiter.isAllowed("u1", max, windowMs));
        System.out.println(limiter.isAllowed("u1", max, windowMs));

        Thread.sleep(210);
        System.out.println(limiter.isAllowed("u1", max, windowMs));
    }
}

