// ── Java helper: calculate EBS cost ─────────────────────────────
public class EbsCostCalculator {
    static double monthlyCostGp3(int sizeGb, int iops, int throughputMBs) {
        double storageCost = sizeGb * 0.08;
        double additionalIops = Math.max(0, iops - 3000) * 0.005;
        double additionalThroughput = Math.max(0, throughputMBs - 125) * 0.04;
        return storageCost + additionalIops + additionalThroughput;
    }

    public static void main(String[] args) {
        System.out.printf("500GB gp3 3000 IOPS:  $%.2f/mo%n",
            monthlyCostGp3(500, 3000, 125));
        System.out.printf("500GB gp3 6000 IOPS:  $%.2f/mo%n",
            monthlyCostGp3(500, 6000, 125));
        System.out.printf("500GB gp3 6000+250MB: $%.2f/mo%n",
            monthlyCostGp3(500, 6000, 250));
    }
}

