// ── Java: S3 lifecycle policy simulator ───────────────────────────
import java.util.*;

public class S3LifecycleDemo {
    enum StorageClass { STANDARD, STANDARD_IA, GLACIER_IR, DEEP_ARCHIVE, DELETED }

    record TransitionRule(int afterDays, StorageClass target) {}

    static StorageClass applyLifecycle(int objectAgeDays, List<TransitionRule> rules) {
        StorageClass current = StorageClass.STANDARD;
        for (TransitionRule rule : rules) {
            if (objectAgeDays >= rule.afterDays()) current = rule.target();
        }
        return current;
    }

    public static void main(String[] args) {
        List<TransitionRule> policy = List.of(
            new TransitionRule(30,  StorageClass.STANDARD_IA),
            new TransitionRule(90,  StorageClass.GLACIER_IR),
            new TransitionRule(365, StorageClass.DEEP_ARCHIVE),
            new TransitionRule(2555, StorageClass.DELETED)
        );

        int[] ages = {10, 30, 91, 400, 2600};
        for (int age : ages) {
            System.out.printf("Age %4d days → %s%n", age, applyLifecycle(age, policy));
        }
    }
}

