import java.util.*;

public class Q3 {
    enum Tier { HOT, WARM, COLD }

    static class StorageObject {
        final String key;
        long lastAccessMs;
        Tier tier = Tier.HOT;
        StorageObject(String key, long now) { this.key = key; this.lastAccessMs = now; }
    }

    static class TieredStorageManager {
        private final Map<String, StorageObject> store = new LinkedHashMap<>();
        private final long hotToWarmMs;
        private final long warmToColdMs;

        TieredStorageManager(long hotToWarmMs, long warmToColdMs) {
            this.hotToWarmMs = hotToWarmMs; this.warmToColdMs = warmToColdMs;
        }

        void put(String key, long nowMs) { store.put(key, new StorageObject(key, nowMs)); }

        void access(String key, long nowMs) {
            StorageObject obj = store.get(key);
            if (obj == null) return;
            if (obj.tier != Tier.HOT) {
                System.out.println("Promoted " + key + " to HOT");
                obj.tier = Tier.HOT;
            }
            obj.lastAccessMs = nowMs;
        }

        void runTiering(long nowMs) {
            for (StorageObject obj : store.values()) {
                long idle = nowMs - obj.lastAccessMs;
                if (obj.tier == Tier.HOT && idle >= hotToWarmMs) {
                    obj.tier = Tier.WARM;
                    System.out.println(obj.key + " demoted to WARM");
                } else if (obj.tier == Tier.WARM && idle >= warmToColdMs) {
                    obj.tier = Tier.COLD;
                    System.out.println(obj.key + " demoted to COLD");
                }
            }
        }

        Tier getTier(String key) {
            StorageObject obj = store.get(key); return obj == null ? null : obj.tier;
        }
    }

    public static void main(String[] args) {
        TieredStorageManager mgr = new TieredStorageManager(100, 100);
        long t = 0;
        mgr.put("video.mp4",   t);
        mgr.put("config.json", t);

        mgr.runTiering(t + 150);
        mgr.runTiering(t + 300);
        mgr.access("video.mp4", t + 350);
        System.out.println("video tier: " + mgr.getTier("video.mp4"));
        System.out.println("config tier: " + mgr.getTier("config.json"));
    }
}
